import{_ as e,o as a,c as i,ag as o}from"./chunks/framework.BqfgOMAh.js";const h=JSON.parse('{"title":"Blueprint Operations","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/blueprint-operations.md","filePath":"en/guide/blueprint-operations.md"}'),n={name:"en/guide/blueprint-operations.md"};function r(l,t,s,d,u,c){return a(),i("div",null,[...t[0]||(t[0]=[o(`<h1 id="blueprint-operations" tabindex="-1">Blueprint Operations <a class="header-anchor" href="#blueprint-operations" aria-label="Permalink to &quot;Blueprint Operations&quot;">​</a></h1><p>NexusFlow&#39;s core capability is operating Unreal Engine Blueprints through AI conversation. Simply describe what you need in natural language, and the AI will automatically analyze the Blueprint and perform the operations.</p><h2 id="ai-blueprint-capabilities" tabindex="-1">AI Blueprint Capabilities <a class="header-anchor" href="#ai-blueprint-capabilities" aria-label="Permalink to &quot;AI Blueprint Capabilities&quot;">​</a></h2><p>NexusFlow provides a set of built-in tools for Blueprint operations. These tools are automatically invoked by the AI — you don&#39;t need to trigger them manually:</p><table tabindex="0"><thead><tr><th>Capability</th><th>Description</th></tr></thead><tbody><tr><td>Read Blueprints</td><td>Retrieve the complete structure of a Blueprint</td></tr><tr><td>Modify Blueprints</td><td>Add, remove, or update Blueprint elements</td></tr><tr><td>Node Search</td><td>Intelligently search for available Blueprint node templates</td></tr><tr><td>Skill Execution</td><td>Run predefined UE operation scripts</td></tr><tr><td>Python Scripts</td><td>Execute custom Python code in UE</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Prerequisites</p><p>Blueprint operations require an active UE Editor connection. Make sure the status bar at the bottom of the sidebar shows a green connection indicator.</p></div><h2 id="reading-blueprints" tabindex="-1">Reading Blueprints <a class="header-anchor" href="#reading-blueprints" aria-label="Permalink to &quot;Reading Blueprints&quot;">​</a></h2><p>When you ask about the current Blueprint, the AI automatically retrieves its JSON representation, including:</p><ul><li>All nodes and their types</li><li>Connection relationships between nodes</li><li>Variable definitions and default values</li><li>Functions and event graphs</li></ul><p><strong>Example conversations:</strong></p><table tabindex="0"><thead><tr><th>Example</th><th>Description</th></tr></thead><tbody><tr><td>&quot;Explain what this Blueprint does&quot;</td><td>AI reads and analyzes the overall Blueprint logic</td></tr><tr><td>&quot;What does this Blueprint do?&quot;</td><td>Get a high-level overview of the Blueprint&#39;s purpose</td></tr><tr><td>&quot;List all variables in this Blueprint&quot;</td><td>View all variable definitions</td></tr><tr><td>&quot;What does the EventBeginPlay do?&quot;</td><td>Explain a specific function or event</td></tr><tr><td>&quot;What are these selected nodes doing?&quot;</td><td>Explain the purpose of the currently selected nodes</td></tr></tbody></table><p>The AI will read the Blueprint structure and explain it to you in clear language.</p><h2 id="modifying-blueprints" tabindex="-1">Modifying Blueprints <a class="header-anchor" href="#modifying-blueprints" aria-label="Permalink to &quot;Modifying Blueprints&quot;">​</a></h2><p>The AI can perform various modifications to Blueprints, including adding, removing, and editing nodes and connections. Modifications are applied through &quot;Blueprint patches&quot; to ensure safe operations.</p><h3 id="node-operations" tabindex="-1">Node Operations <a class="header-anchor" href="#node-operations" aria-label="Permalink to &quot;Node Operations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Example</th><th>Description</th></tr></thead><tbody><tr><td>&quot;Add a Print String node&quot;</td><td>Create a new node</td></tr><tr><td>&quot;Add a Delay node after BeginPlay with a 2-second delay&quot;</td><td>Create and connect with specific parameters</td></tr><tr><td>&quot;Delete the selected nodes&quot;</td><td>Remove the currently selected nodes</td></tr><tr><td>&quot;Change the Delay node&#39;s duration to 5 seconds&quot;</td><td>Modify a node&#39;s property value</td></tr></tbody></table><h3 id="connection-operations" tabindex="-1">Connection Operations <a class="header-anchor" href="#connection-operations" aria-label="Permalink to &quot;Connection Operations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Example</th><th>Description</th></tr></thead><tbody><tr><td>&quot;Connect BeginPlay to Print String&quot;</td><td>Create a connection between nodes</td></tr><tr><td>&quot;Disconnect the link between Delay and Print String&quot;</td><td>Remove a connection</td></tr><tr><td>&quot;Connect the return value of GetPlayerController to Cast&quot;</td><td>Connect specific pins</td></tr></tbody></table><h3 id="batch-operations" tabindex="-1">Batch Operations <a class="header-anchor" href="#batch-operations" aria-label="Permalink to &quot;Batch Operations&quot;">​</a></h3><p>For complex logic, the AI can create multiple nodes and connections in a single operation:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Add a Branch node, connect the condition to IsValid&#39;s result, and execute Print String on True&quot;</span></span>
<span class="line"><span>&quot;Create a simple timer logic: BeginPlay → SetTimer → callback function prints a message&quot;</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Note</p><p>After the AI modifies a Blueprint, the changes are automatically reflected in the UE Editor. If the result isn&#39;t what you expected, you can use <strong>Ctrl+Z</strong> in UE to undo the operation.</p></div><h2 id="creating-blueprint-logic" tabindex="-1">Creating Blueprint Logic <a class="header-anchor" href="#creating-blueprint-logic" aria-label="Permalink to &quot;Creating Blueprint Logic&quot;">​</a></h2><p>You can ask the AI to create complete Blueprint logic from scratch:</p><table tabindex="0"><thead><tr><th>Example</th><th>Description</th></tr></thead><tbody><tr><td>&quot;Create a character movement Blueprint&quot;</td><td>Build a complete movement logic</td></tr><tr><td>&quot;Add an input event that triggers on pressing E&quot;</td><td>Create an input event handler</td></tr><tr><td>&quot;Create a timer that fires every 2 seconds&quot;</td><td>Build timer-based logic</td></tr><tr><td>&quot;Implement a basic health system&quot;</td><td>Create a full system with variables and logic</td></tr><tr><td>&quot;Create a logic that rotates 90 degrees every 3 seconds&quot;</td><td>Time-based transformation</td></tr></tbody></table><p>The AI will automatically create the necessary nodes, variables, and connections based on your description.</p><h2 id="variable-management" tabindex="-1">Variable Management <a class="header-anchor" href="#variable-management" aria-label="Permalink to &quot;Variable Management&quot;">​</a></h2><p>Manage Blueprint variables through conversation:</p><table tabindex="0"><thead><tr><th>Example</th><th>Description</th></tr></thead><tbody><tr><td>&quot;Create a Float variable named PlayerHealth with a default value of 100&quot;</td><td>Create a typed variable</td></tr><tr><td>&quot;Create a boolean variable called IsActive&quot;</td><td>Create a simple variable</td></tr><tr><td>&quot;Rename the variable to PlayerHealth&quot;</td><td>Rename existing variables</td></tr><tr><td>&quot;Set the default value of MaxHealth to 100&quot;</td><td>Change default values</td></tr><tr><td>&quot;Delete the TempData variable&quot;</td><td>Remove variables</td></tr></tbody></table><h2 id="function-management" tabindex="-1">Function Management <a class="header-anchor" href="#function-management" aria-label="Permalink to &quot;Function Management&quot;">​</a></h2><p>Manage custom functions in Blueprints:</p><table tabindex="0"><thead><tr><th>Example</th><th>Description</th></tr></thead><tbody><tr><td>&quot;Create a function called CalculateDamage with a BaseDamage (Float) parameter&quot;</td><td>Create with parameters</td></tr><tr><td>&quot;Add default value initialization logic to the InitializePlayer function&quot;</td><td>Add logic to existing functions</td></tr><tr><td>&quot;Add a return value to the GetPlayerInfo function&quot;</td><td>Modify function signatures</td></tr></tbody></table><h2 id="event-management" tabindex="-1">Event Management <a class="header-anchor" href="#event-management" aria-label="Permalink to &quot;Event Management&quot;">​</a></h2><p>Manage Blueprint events:</p><table tabindex="0"><thead><tr><th>Example</th><th>Description</th></tr></thead><tbody><tr><td>&quot;Add an ActorBeginOverlap event&quot;</td><td>Add a standard event</td></tr><tr><td>&quot;Add rotation logic in EventTick&quot;</td><td>Add logic to existing events</td></tr><tr><td>&quot;Create a custom event called OnPlayerDeath&quot;</td><td>Create custom events</td></tr></tbody></table><h2 id="node-search" tabindex="-1">Node Search <a class="header-anchor" href="#node-search" aria-label="Permalink to &quot;Node Search&quot;">​</a></h2><p>When the AI needs to find specific types of nodes, it uses intelligent search to find the most suitable node templates:</p><ul><li><strong>Node Template Search</strong>: Uses semantic search to find available Blueprint node types</li><li><strong>Blueprint Node Search</strong>: Searches for existing nodes within the current Blueprint</li></ul><table tabindex="0"><thead><tr><th>Example</th><th>Description</th></tr></thead><tbody><tr><td>&quot;Is there a node for getting the player&#39;s location?&quot;</td><td>Search node templates</td></tr><tr><td>&quot;Find nodes related to collision detection&quot;</td><td>Semantic search for Blueprint nodes</td></tr><tr><td>&quot;What math operation nodes are available?&quot;</td><td>Browse nodes in a specific category</td></tr></tbody></table><p>This process is automatic — when you describe your needs, the AI automatically searches for matching nodes to complete the operation.</p><h2 id="ue-skills" tabindex="-1">UE Skills <a class="header-anchor" href="#ue-skills" aria-label="Permalink to &quot;UE Skills&quot;">​</a></h2><p>NexusFlow includes a built-in UE Skills system that provides advanced Blueprint operation capabilities. The AI can automatically search, load, and execute relevant Skills.</p><p>Skills currently cover the following capabilities:</p><ul><li><strong>Blueprint</strong> — Blueprint creation, management, and 60+ node operations</li><li><strong>Asset</strong> — Asset creation, import, and management</li><li><strong>Data</strong> — Data table and curve table operations</li><li><strong>Lighting</strong> — Lighting setup and configuration</li></ul><p><strong>Usage examples:</strong></p><table tabindex="0"><thead><tr><th>Example</th><th>Description</th></tr></thead><tbody><tr><td>&quot;Create a new Actor Blueprint&quot;</td><td>AI selects the Blueprint Skill</td></tr><tr><td>&quot;Import this FBX as a static mesh&quot;</td><td>AI selects the Asset Skill</td></tr><tr><td>&quot;Add a row to the damage data table&quot;</td><td>AI selects the Data Skill</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You don&#39;t need to know the implementation details of Skills. Just describe what you want to accomplish, and the AI will automatically select the appropriate Skill.</p></div><h2 id="python-script-execution" tabindex="-1">Python Script Execution <a class="header-anchor" href="#python-script-execution" aria-label="Permalink to &quot;Python Script Execution&quot;">​</a></h2><p>For special operations not covered by Skills, the AI can write and execute Python scripts to directly manipulate the UE Editor:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Batch rename all Blueprints starting with BP_&quot;</span></span>
<span class="line"><span>&quot;Export position information of all Actors in the current level&quot;</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Security Note</p><p>Python scripts execute within the UE Editor with full editor access. NexusFlow performs security checks before execution.</p></div><h2 id="effective-prompting-tips" tabindex="-1">Effective Prompting Tips <a class="header-anchor" href="#effective-prompting-tips" aria-label="Permalink to &quot;Effective Prompting Tips&quot;">​</a></h2><p>Follow these tips to get better AI responses:</p><h3 id="✅-best-practices" tabindex="-1">✅ Best Practices <a class="header-anchor" href="#✅-best-practices" aria-label="Permalink to &quot;✅ Best Practices&quot;">​</a></h3><ul><li><strong>Be specific</strong>: &quot;Add a Delay node after BeginPlay with a 2-second delay then execute Print String&quot; is much clearer than &quot;Add a node&quot;</li><li><strong>Provide context</strong>: &quot;I&#39;m building a damage system for a shooter game&quot; helps the AI understand your overall goal</li><li><strong>Break down complex tasks</strong>: Split complex requirements into multiple steps and complete them one at a time</li><li><strong>Use UE terminology</strong>: Use accurate UE concept names (e.g., Actor, Component, Blueprint)</li><li><strong>Select first</strong>: Select specific nodes before asking — the AI can better understand your intent with selection context</li></ul><h3 id="❌-things-to-avoid" tabindex="-1">❌ Things to Avoid <a class="header-anchor" href="#❌-things-to-avoid" aria-label="Permalink to &quot;❌ Things to Avoid&quot;">​</a></h3><ul><li>Vague descriptions like &quot;Change the Blueprint&quot;</li><li>Overly complex requests in a single message</li><li>Requesting Blueprint operations without opening a Blueprint first</li></ul><div class="warning custom-block"><p class="custom-block-title">Make Sure a Blueprint is Open</p><p>Before requesting Blueprint operations, make sure you have the target Blueprint open in the UE Editor. The AI needs to read Blueprint information to perform operations.</p></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./ai-chat">AI Chat</a> — Explore the chat interface in detail</li><li><a href="./quick-menu">UE Quick Menu</a> — 17 AI operations via right-click menus and toolbars</li><li><a href="./settings">Settings</a> — Customize NexusFlow to your preferences</li></ul>`,60)])])}const m=e(n,[["render",r]]);export{h as __pageData,m as default};
